exports.EmptyFolder = async (dirName) => {
  if (await fs.readdirSync(dirName).length > 2) {
    await fs.readdir(dirName, async (err, files) => {
      for (const file of files) {
        await fs.unlink(path.join(dirName, file), err => {
        });
      }
    });
  }
}

