exports.mapSTDItems = async (prodItems, userRole) => {
  return (function () {
    let items = [];
    let prodItem = prodItems[0].dataValues;
    for (var i = 0; prodItem.StandardizedGroups.length > i; i++) {
      let stdGroup = prodItem.StandardizedGroups[i].dataValues;
      for (var j = 0; stdGroup.StandardizedSizes.length > j; j++) {
        items.push({});
        items[items.length - 1]['prod_name'] = prodItems[0].dataValues.prod_name;
        items[items.length - 1]['prod_id'] = prodItems[0].dataValues.id
        items[items.length - 1]['std_group'] = stdGroup.title;
        let stdSize = stdGroup.StandardizedSizes[j].dataValues;
        items[items.length - 1]['row_id'] = stdSize.id + '_' + stdGroup.id;
        items[items.length - 1]['size_cm'] = stdSize.itemSizeCm.dataValues.itemSize_title;
        items[items.length - 1]['size_in'] = stdSize.itemSizeIn.dataValues.itemSize_title;
        items[items.length - 1]['stdSize_id'] = stdSize.id;
        items[items.length - 1]['stdGroup_id'] = stdGroup.id;
        items[items.length - 1]['item_status'] = stdSize.status;
        items[items.length - 1]['highlighted'] = [];

        for (var k = 0; stdSize.StandardizedDetails.length > k; k++) {
          let stdDetail = stdSize.StandardizedDetails[k].dataValues;

          for (var m = 0; stdDetail.StandardizedVendors.length > m; m++) {

            if (stdDetail.StandardizedVendors[m].dataValues.highlighted) {
              items[items.length - 1]['highlighted'].push(`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}_${stdDetail.StandardizedVendors[m].dataValues.highlighted}`);
            }

            if (userRole == 'vendor') {
              items[items.length - 1]['width'] = stdDetail.StandardizedVendors[m].dataValues.width;
              items[items.length - 1]['height'] = stdDetail.StandardizedVendors[m].dataValues.height;
              items[items.length - 1]['length'] = stdDetail.StandardizedVendors[m].dataValues.length;
            }
            if (userRole == 'admin' || userRole == 'production' || userRole == 'vendor') {
              items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = stdDetail.StandardizedVendors[m].dataValues.price;
            } else {
              if (stdDetail.StandardizedVendors[m].dataValues.price) {
                items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = true;
              } else {
                items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = false;
              }
            }
          }
        }
        if (userRole == 'vendor') {
          if (items[items.length - 1]['highlighted'].length == 0) {
            items.splice(items.length - 1, 1);
          }
        }
      }
    }
    return items;
  })();
}

exports.STDItemToRFQItem = async (prodItems, body) => {
  return (function () {
    let items = [];
    for (var u = 0; prodItems.length > u; u++) {
      let prodItem = prodItems[u][0];

      for (var i = 0; prodItem.StandardizedGroups.length > i; i++) {
        let stdGroup = prodItem.StandardizedGroups[i].dataValues;
        for (var j = 0; stdGroup.StandardizedSizes.length > j; j++) {
          items.push({});
          //prod table
          items[items.length - 1].prod_id = prodItem.id;
          items[items.length - 1].rfqItem_udf2 = prodItem.material_id_fk;
          items[items.length - 1].rfqItem_picturethumb = prodItem.prod_img_thumbnail;
          items[items.length - 1].rfqItem_picture = prodItem.prod_img_fullsize;
          items[items.length - 1].rfqItem_udf4 = prodItem.construction_id_fk
          //group table
          items[items.length - 1].rfqItem_depth = stdGroup.depth_id_fk
          items[items.length - 1].rfqItem_case_pack = stdGroup.casePack
          items[items.length - 1].rfqItem_quantity = stdGroup.qty
          //size table
          let stdSize = stdGroup.StandardizedSizes[j].dataValues;
          items[items.length - 1].rfqItem_size_l_w = stdSize.size_in_id_fk;
          for (var k = 0; stdSize.StandardizedDetails.length > k; k++) {
            //version table
            var stdVersion = stdSize.StandardizedDetails[k].dataValues.StandardizedVersion.dataValues;
            items[items.length - 1].rfqItem_udf3 = stdVersion.treatment_id_fk
          }
          items[items.length - 1].rfqItem_style_number = generatePriceCode() //id
          //desc size + depth + prod type + version + element details from the group
          let groupTitleinArray = stdGroup.title.split(' ');
          let additionalDesc = '';
          for (let l = 7; groupTitleinArray.length > l; l++) {
            additionalDesc += ' ' + groupTitleinArray[l]
          }
          items[items.length - 1].rfqItem_description = `${prodItem.prod_name} ${stdSize.itemSizeIn.dataValues.itemSize_title}" x${stdGroup.itemDepth.dataValues.itemDepth_title}" ${stdVersion.title}`
          if (additionalDesc)
            items[items.length - 1].rfqItem_description += `, ${additionalDesc}`
          //req info  
          if (body.RFQGroup) {
            items[items.length - 1].rfqItem_rfq_group = body.RFQGroup.RFQGroup_id //id
            items[items.length - 1].rfqItem_license = body.lic// title
            items[items.length - 1].rfqItem_divCode_id_fk = body.div// title
            items[items.length - 1].rfqItem_active = 1
            items[items.length - 1].rfqItem_created_date = new Date()
            items[items.length - 1].rfqItem_date_modified = new Date().toISOString()
            items[items.length - 1].rfq_container_id_fk = 1 //default RFQ container

          }
        }
      }
    }
    return items;
  })();
}

