function generatePriceCode() {
  let price_code = 'STD_';
  let randomStr = Math.random().toString(36).slice(2, 7).toUpperCase();
  let month = new Date().getMonth();
  let day = new Date().getDate();
  let hour = new Date().getHours();
  let minute = new Date().getMinutes();
  let millisecond = new Date().getMilliseconds();
  price_code += randomStr + month + day + "_" + hour + minute + millisecond;
  return price_code
}

