/**
 * Get list of user's grid views for a specific grid
 * Returns user's views + Default view
 */
Customer.getUserGridViews = async (req, result) => {
  try {
    let user_info = await getUserInfo(req.headers.authorization);
    let userDetail = await findUserInfoWithEmail(user_info);

    if (!userDetail && user_info.role === 'vendor') {
      userDetail = await findVendorInfoWithEmail(user_info);
      if (userDetail) userDetail.id = userDetail.vendor_id;
    }

    const { grid_id } = req.body;
    const userId = userDetail?.id || null;

    // Get user's views
    const userViews = await sql.GridViewState.findAll({
      where: {
        user_id_fk: userId,
        grid_id: grid_id
      },
      attributes: ['view_name', 'is_default'],
      order: [['view_name', 'ASC']]
    });

    // Get Default view (global)
    const defaultView = await sql.GridViewState.findOne({
      where: {
        user_id_fk: null,
        grid_id: grid_id,
        view_name: 'Default'
      },
      attributes: ['view_name']
    });

    // Combine results, ensuring Default is first if it exists
    let views = [];
    if (defaultView) {
      views.push({ view_name: 'Default', is_default: false });
    }

    userViews.forEach(v => {
      if (v.view_name !== 'Default') {
        views.push({
          view_name: v.view_name,
          is_default: !!v.is_default
        });
      }
    });

    result(null, views);
  } catch (err) {
    console.error('Error getting user grid views:', err);
    result(err, null);
  }
};

