/**
 * Set which custom view is default for this user+grid, or clear all (fall back to global Default).
 * Body: { grid_id, view_name } to set, or { grid_id, clear: true } to clear.
 */
Customer.setGridDefaultView = async (req, result) => {
  try {
    let user_info = await getUserInfo(req.headers.authorization);
    let userDetail = await findUserInfoWithEmail(user_info);

    if (!userDetail && user_info.role === 'vendor') {
      userDetail = await findVendorInfoWithEmail(user_info);
      if (userDetail) userDetail.id = userDetail.vendor_id;
    }

    const userId = userDetail?.id || null;
    const { grid_id, view_name, clear } = req.body;

    if (!grid_id) {
      return result({ message: 'grid_id is required.' }, null);
    }
    if (userId == null) {
      return result({ message: 'User not found.' }, null);
    }

    await sql.GridViewState.update(
      { is_default: false, updated_at: new Date() },
      {
        where: {
          user_id_fk: userId,
          grid_id: grid_id
        },
        individualHooks: true
      }
    );

    if (clear === true || clear === 'true') {
      return result(null, { success: true });
    }

    if (!view_name || typeof view_name !== 'string') {
      return result({ message: 'view_name is required unless clear is true.' }, null);
    }

    const trimmed = view_name.trim();
    if (trimmed === 'Default') {
      return result({ message: 'Cannot set Default as a custom default; use clear default instead.' }, null);
    }

    const row = await sql.GridViewState.findOne({
      where: {
        user_id_fk: userId,
        grid_id: grid_id,
        view_name: trimmed
      }
    });

    if (!row) {
      return result({ message: 'View not found for this user.' }, null);
    }

    await sql.GridViewState.update(
      { is_default: true, updated_at: new Date() },
      {
        where: {
          user_id_fk: userId,
          grid_id: grid_id,
          view_name: trimmed
        },
        individualHooks: true
      }
    );

    result(null, { success: true, view_name: trimmed });
  } catch (err) {
    console.error('Error setting grid default view:', err);
    result(err, null);
  }
};


