      const data = await sql.vendor.findOne({
        where: {
          vendor_email: user.email
        }
      });
      if (data) {
        user.factory_id = data.factory_id_fk;
        user.vendor_id = data.vendor_id;
      }
    }
    if (user.factory_id) {
      // Lazy per-vendor sweep: archive this factory's own quote rows that were priced
      // and quoted >3 months ago. Per-vendor (RFQVendor_archived), so it never affects
      // Sourcing or other factories. Failure here must not break the listing.
      try {
        await archiveStaleVendorQuotes(sql, user.factory_id);
      } catch (e) {
        console.warn('archiveStaleVendorQuotes skipped:', e.message);
      }

      // For vendors the archive/active split is driven by THEIR own quote row, not the
      // global RFQItem.rfqItem_archive flag. Archive tab → archived rows; active → the rest.
      const vendorArchived = req.body.status == 'archive'
        ? true
