      if (req.body.filterd_rfq == 'true') {
        // Allow showing the highlighted item OR any item assigned to this vendor/factory
        condition = {
          '$RFQVendors.RFQVendor_archived$': vendorArchived,
          '$RFQItem.rfqItem_divCode_id_fk$': { [Op.or]: divisionCodeArray },
          '$RFQItem.rfqItem_active$': { [Op.or]: divisionStatusArray },
          [Op.or]: [
            { '$RFQVendors.vendor_id_fk$': { [Op.or]: [user.vendor_id, user.factory_id] } },
            { 'rfqItem_style_number': req.body.highlightedItem }
          ]
        }
        order = [Sequelize.literal('"RFQVendor_id" DESC')]
      } else {
        condition = {
          '$RFQVendors.RFQVendor_archived$': vendorArchived,
          '$RFQItem.rfqItem_divCode_id_fk$': {
            [Op.or]: divisionCodeArray
          },
          '$RFQItem.rfqItem_active$': {
            [Op.or]: divisionStatusArray
          },
          '$RFQVendors.vendor_id_fk$': user.factory_id
        }
        order = [Sequelize.literal('"RFQVendor_id" DESC')]
      }
    }



  } else {

    condition = {
      '$RFQItem.rfqItem_archive$': status,
      '$RFQItem.rfqItem_divCode_id_fk$': {
        [Op.or]: divisionCodeArray
      },
      '$RFQItem.rfqItem_active$': {
