  let rfqVendorsInclude = {
    model: sql.RFQVendor,
    as: 'RFQVendors',
    required: false,
    include: [{
      model: sql.Factory,
      as: 'Factory',
      required: false
    }]
  };
  if (user.role === 'vendor') {
    rfqVendorsInclude.where = { vendor_id_fk: user.factory_id };
  }

  await sql.RFQItem.findAll({
    logging: console.log,
    order: order,
