Customer.getAll = async (req, result) => {
  let token = req.headers.authorization;
  let user = await getUserInfo(token)
  let status;
  let condition;
  let order;
  let divisionCodeArray = ['Lic,Gen', 'Gen,Lic'];
  let divisionStatusArray = [];
  let subQuery = false;
  if (req.body.status == 'archive') {
    status = 1
  } else {
    status = null
  }
  for (var i = 0; req.body.divisionCode.length > i; i++) {
    divisionCodeArray.push(req.body.divisionCode[i].divCode_code)
  }
  for (var i = 0; req.body.divisionStatus.length > i; i++) {
    divisionStatusArray.push(req.body.divisionStatus[i].RFQItemStatus_id)
  }
  if (user.role == 'vendor') {
    if (!user.factory_id && user.email) {
      const data = await sql.vendor.findOne({
        where: {
          vendor_email: user.email
        }
      });
      if (data) {
        user.factory_id = data.factory_id_fk;
        user.vendor_id = data.vendor_id;
      }
    }
    if (user.factory_id) {
      // Lazy per-vendor sweep: archive this factory's own quote rows that were priced
      // and quoted >3 months ago. Per-vendor (RFQVendor_archived), so it never affects
      // Sourcing or other factories. Failure here must not break the listing.
      try {
        await archiveStaleVendorQuotes(sql, user.factory_id);
      } catch (e) {
        console.warn('archiveStaleVendorQuotes skipped:', e.message);
      }

      // For vendors the archive/active split is driven by THEIR own quote row, not the
      // global RFQItem.rfqItem_archive flag. Archive tab → archived rows; active → the rest.
      const vendorArchived = req.body.status == 'archive'
        ? true
        : { [Op.or]: [false, null] };

      if (req.body.filterd_rfq == 'true') {
        // Allow showing the highlighted item OR any item assigned to this vendor/factory
        condition = {
          '$RFQVendors.RFQVendor_archived$': vendorArchived,
          '$RFQItem.rfqItem_divCode_id_fk$': { [Op.or]: divisionCodeArray },
          '$RFQItem.rfqItem_active$': { [Op.or]: divisionStatusArray },
          [Op.or]: [
            { '$RFQVendors.vendor_id_fk$': { [Op.or]: [user.vendor_id, user.factory_id] } },
            { 'rfqItem_style_number': req.body.highlightedItem }
          ]
        }
        order = [Sequelize.literal('"RFQVendor_id" DESC')]
      } else {
        condition = {
          '$RFQVendors.RFQVendor_archived$': vendorArchived,
          '$RFQItem.rfqItem_divCode_id_fk$': {
            [Op.or]: divisionCodeArray
          },
          '$RFQItem.rfqItem_active$': {
            [Op.or]: divisionStatusArray
          },
          '$RFQVendors.vendor_id_fk$': user.factory_id
        }
        order = [Sequelize.literal('"RFQVendor_id" DESC')]
      }
    }



  } else {

    condition = {
      '$RFQItem.rfqItem_archive$': status,
      '$RFQItem.rfqItem_divCode_id_fk$': {
        [Op.or]: divisionCodeArray
      },
      '$RFQItem.rfqItem_active$': {
        [Op.or]: divisionStatusArray
      },
    }
    //order = [Sequelize.literal('"RFQGroup_name"'), Sequelize.literal('"rfqItem_id" DESC')]
    order = [Sequelize.literal('"rfqItem_id" DESC')]
    subQuery = true
  }

  const rfqVendorsInclude = buildRfqVendorsInclude(sql, user);

  try {
    const [data, merchGroupData, whsecost] = await Promise.all([
      sql.RFQItem.findAll({
        order: order,
        subQuery: subQuery,
        attributes: { exclude: RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES },
        as: 'RFQItem',
        where: condition,
        include: buildRfqListLookupIncludes(sql, rfqVendorsInclude),
      }),
      getCachedMerchGroup(sql),
      getCachedWhsePrice(sql),
    ]);

    if (!data) {
      result(null, null);
      return;
    }

    const merchGroupMap = buildMerchGroupMap(merchGroupData);
    let items = await utility.remapRFQItem(data, merchGroupData, {
      merchGroupMap,
      whsecost,
    });
    items = items.sort(function (a, b) {
      return (a['Price Code'] == req.body.highlightedItem) ? -1 : 1;
    });

    result(null, items);
  } catch (err) {
    result(err, null);
  }
};

function array_move(arr, old_index, new_index) {
  if (new_index >= arr.length) {
    var k = new_index - arr.length + 1;
    while (k--) {
      arr.push(undefined);
    }
  }
  arr.splice(new_index, 0, arr.splice(old_index, 1)[0]);
  return arr; // for testing
};
